/**
 * Lankkurullakioski — dynamic theme from hero image (canvas palette extraction)
 * Place your image at assets/hero.jpg (or .png / .webp / .jpeg) or hero.jpg in site root.
 */
(function () {
  "use strict";

  var HERO_URLS = [
    "assets/hero.jpg",
    "assets/hero.jpeg",
    "assets/hero.png",
    "assets/hero.webp",
    "hero.jpg",
    "hero.jpeg",
    "hero.png",
    "hero.webp",
