      return;
    }
    loadImage(urls[index], function (img) {
      if (img && img.naturalWidth > 0) processImage(img, urls[index]);
      else tryNext(urls, index + 1);
    });
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", function () {
      tryNext(HERO_URLS, 0);
    });
