function extractPalette(imageData, width, height) {
  var data = imageData.data;
  var n = width * height;
  var sumR = 0,
    sumG = 0,
    sumB = 0;
  var bestSat = -1;
  var best = { r: 232, g: 157, b: 71 };
  var step = 4 * 3;

  for (var i = 0; i < data.length; i += step) {
    var r = data[i];
    var g = data[i + 1];
    var b = data[i + 2];
    var a = data[i + 3];
    if (a < 20) continue;
    sumR += r;
    sumG += g;
    sumB += b;
    var lum = relativeLuminance(r, g, b);
    var sat = saturationRgb(r, g, b);
    if (lum > 0.08 && lum < 0.92 && sat > bestSat) {
      bestSat = sat;
      best = { r: r, g: g, b: b };
    }
  }

  var count = Math.floor(data.length / step / 4) || 1;
  var avg = {
    r: Math.round(sumR / count),
    g: Math.round(sumG / count),
    b: Math.round(sumB / count),
  };

  if (bestSat < 0.12) {
    var hsl = rgbToHsl(avg.r, avg.g, avg.b);
    best = hslToRgb(38, clamp(hsl.s + 0.35, 0.55, 0.95), clamp(hsl.l + 0.15, 0.45, 0.62));
